+    #[fcp_async_core::runtime::test]
+    async fn test_health_includes_auth_info() {
+        let mut connector = S3Connector::new();
+        connector
+            .handle_configure(json!({
+                "access_key_id": "AKIAIOSFODNN7EXAMPLE",
+                "secret_access_key": "secret",
